import{_ as t,o as a,c as r,a2 as i}from"./chunks/framework.BWuWLRhz.js";const h=JSON.parse('{"title":"Epic: Data Sovereignty","description":"","frontmatter":{},"headers":[],"relativePath":"epics/data-sovereignty.md","filePath":"epics/data-sovereignty.md"}'),o={name:"epics/data-sovereignty.md"};function s(l,e,n,d,c,p){return a(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="epic-data-sovereignty" tabindex="-1">Epic: Data Sovereignty <a class="header-anchor" href="#epic-data-sovereignty" aria-label="Permalink to &quot;Epic: Data Sovereignty&quot;">​</a></h1><blockquote><p>Users own their data — they can export it, import it, migrate it to another instance, delete it entirely, and trust that it is encrypted at rest.</p></blockquote><h2 id="status" tabindex="-1">Status <a class="header-anchor" href="#status" aria-label="Permalink to &quot;Status&quot;">​</a></h2><p>⏳ In Progress</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>&quot;Data sovereignty&quot; is a core Sovereign promise: no lock-in, no silent retention. This epic covers the full data lifecycle — Drizzle-kit migrations and backup/restore (upgrade safety), self-service export/import (portability), per-plugin database isolation (plugin data stays with its plugin), self-delete (the right to be forgotten), and encryption at rest (post-v1, opt-in). User data deletion (epic task 1.7) is complete; encryption at rest is scheduled post-v1.</p><h2 id="tasks" tabindex="-1">Tasks <a class="header-anchor" href="#tasks" aria-label="Permalink to &quot;Tasks&quot;">​</a></h2><h4 id="✅-8-1-—-deployment-upgrade-strategy-rfc-0006" tabindex="-1">✅ 8.1 — Deployment &amp; upgrade strategy (RFC 0006) <a class="header-anchor" href="#✅-8-1-—-deployment-upgrade-strategy-rfc-0006" aria-label="Permalink to &quot;✅ 8.1 — Deployment &amp; upgrade strategy (RFC 0006)&quot;">​</a></h4><p><strong>Goal:</strong> Implement the tiered, low-downtime upgrade model from RFC 0006 / SRS §3.15. Depends on the CI pipeline (Task 0.5.07) for image publishing.</p><p><strong>Deliverables:</strong></p><ul><li>CI builds + pushes semver-tagged runtime/auth images; <code>docker-compose.prod.yml</code> references <code>image:</code> tags pinned by <code>SOVEREIGN_VERSION</code> (build-from-source kept as a fallback)</li><li>Graceful shutdown (SIGTERM draining + <code>stop_grace_period</code>) in both standalone servers; blue-green documented as the advanced path</li><li>drizzle-kit migrations under expand-contract: <code>drizzle.config</code>, <code>packages/db/migrations/</code>, load-bearing <code>runMigrations</code>, <code>schema_migrations</code> ledger, single-writer advisory lock, fail-fast</li><li><code>sv backup</code>/<code>sv restore</code> (dialect-aware, DB + avatars) + automatic pre-upgrade snapshot; tag-pinned rollback procedure</li><li>Startup version gate (downgrade guard) surfaced in <code>/api/admin/health</code></li><li>Docs: <code>docs/self-hosting.md</code> + <code>docs/upgrade.md</code> rewrite</li></ul><p><strong>Dependencies:</strong> Task 0.5.07 (CI / image registry)</p><p><strong>SRS reference:</strong> RFC 0006, SRS §3.15, NFR-01/04/10</p><p><strong>Review checklist:</strong></p><ul><li>An upgrade is <code>pull</code> + recreate (no host build); rollback = repin previous tag + <code>sv restore</code></li><li>A failed migration leaves the DB un-served and the pre-upgrade snapshot intact</li><li>Graceful restart drops no in-flight requests behind the reverse proxy</li></ul><hr><h4 id="✅-8-2-—-user-data-portability-rfc-0007" tabindex="-1">✅ 8.2 — User data portability (RFC 0007) <a class="header-anchor" href="#✅-8-2-—-user-data-portability-rfc-0007" aria-label="Permalink to &quot;✅ 8.2 — User data portability (RFC 0007)&quot;">​</a></h4><p><strong>Goal:</strong> Implement self-service export/import/migration from RFC 0007 / SRS §3.16. The reserved <code>sdk.portability</code> surface and <code>data:export</code>/<code>data:import</code> permissions land as stubs first (sequenced after RFC 0005&#39;s stubs).</p><p><strong>Deliverables:</strong></p><ul><li>SDK: <code>sdk.portability.provideExport</code>/<code>provideImport</code> (replace stubs), runtime-mediated with injected user/tenant</li><li>Runtime: export assembler + import validator (format/schema-version checks, ID remap), plugin-resolver registry, versioned-ZIP streaming, owner gating</li><li>Account: a <strong>Data</strong> tab — export (download) + import/restore (upload) with a per-section result summary</li><li>Reference plugins implement export/import resolvers</li><li>Export/import events audited via <code>sdk.activity</code> (Task 0.5.12)</li></ul><p><strong>Dependencies:</strong> Task 0.5.05 (<code>sdk.db</code>), Task 0.5.12 (audit), Task 1.0.01 (optional bundle encryption, post-v1)</p><p><strong>SRS reference:</strong> RFC 0007, SRS §3.16, §5 (<code>data:export</code>/<code>data:import</code>)</p><p><strong>Review checklist:</strong></p><ul><li>Export produces a versioned ZIP (<code>manifest.json</code> + <code>platform/</code> + <code>plugins/&lt;id&gt;/</code>); a plugin only ever exports/imports the current user&#39;s own data</li><li>Import remaps IDs (no FK breakage), is additive by default, and skips unknown plugins with a warning</li><li>Cross-instance import maps the subject user to the target instance&#39;s current user</li></ul><hr><h4 id="✅-8-3-—-per-plugin-database" tabindex="-1">✅ 8.3 — Per-plugin database <a class="header-anchor" href="#✅-8-3-—-per-plugin-database" aria-label="Permalink to &quot;✅ 8.3 — Per-plugin database&quot;">​</a></h4><blockquote><p>Full entry: <strong>[3.13]</strong> in <a href="./plugins-runtime.html">plugins-runtime.md</a> — Per-plugin database. This task provisions the isolated storage layer that keeps plugin data physically separate from the platform DB — a key component of data sovereignty.</p></blockquote><hr><h4 id="📋-8-4-—-user-data-deletion" tabindex="-1">📋 8.4 — User data deletion <a class="header-anchor" href="#📋-8-4-—-user-data-deletion" aria-label="Permalink to &quot;📋 8.4 — User data deletion&quot;">​</a></h4><blockquote><p>Full entry: <strong>[1.7]</strong> in <a href="./users-auth.html">users-auth.md</a> — User data deletion. This task gives users the right to permanently delete all their data, with plugin handlers called via <code>sdk.portability.provideDelete</code>.</p></blockquote><hr><h4 id="📋-8-5-—-encryption-at-rest-field-level-tier-2–4-rfc-0008" tabindex="-1">📋 8.5 — Encryption at rest &amp; field-level, Tier 2–4 (RFC 0008) <a class="header-anchor" href="#📋-8-5-—-encryption-at-rest-field-level-tier-2–4-rfc-0008" aria-label="Permalink to &quot;📋 8.5 — Encryption at rest &amp; field-level, Tier 2–4 (RFC 0008)&quot;">​</a></h4><p><strong>Goal:</strong> The deferred, crypto-heavy tiers of RFC 0008 / SRS §3.17 — shipped <strong>after v1</strong>. Tier 2 (at-rest encryption + key management), Tier 3 (field-level via <code>sdk.crypto</code>), and the charting of Tier 4 (zero-knowledge E2EE). The reserved <code>sdk.crypto</code> surface + <code>crypto:use</code> permission land as <code>NotImplementedError</code> stubs first (after RFC 0005&#39;s stubs).</p><p><strong>Deliverables:</strong></p><ul><li>Tier 2: local-keyfile envelope key management (master KEK → wrapped DEKs; fail-fast when enabled); SQLCipher DB encryption (<code>better-sqlite3-multiple-ciphers</code>); encrypted backups (amends Task 0.5.13) + encrypted export bundles (amends Task 0.5.14); avatar/blob encryption</li><li>Tier 3: <code>sdk.crypto</code> field-level encrypt/decrypt (per-user DEK) + <code>crypto:use</code> enforcement; optional blind indexes</li><li>Tier 4: zero-knowledge E2EE remains charted (per-plugin opt-in, aligned with the federation direction) — not built</li><li>New env vars (<code>SOVEREIGN_ENCRYPTION</code>, key/keyfile, backup passphrase) → <code>.env.example</code> + <code>docs/self-hosting.md</code> + docs-parity; <strong>Docker/native-dep impact</strong> (SQLCipher in image build + <code>allowBuilds</code>)</li></ul><p><strong>Dependencies:</strong> Task 0.5.15 (Tier 0–1), Task 0.5.13 (backups), Task 0.5.14 (exports)</p><p><strong>SRS reference:</strong> RFC 0008 (Tiers 2–4), SRS §3.17, §5 (<code>crypto:use</code>), NFR-02/07/08/09</p><p><strong>Review checklist:</strong></p><ul><li>A stolen disk / leaked backup yields ciphertext; the docs state plainly that server-held keys do not defend against a curious operator or RCE</li><li>Encryption is opt-in and fails fast when enabled without a key; rotation re-wraps DEKs without bulk re-encryption</li><li>Field-level encryption is gated by <code>crypto:use</code>; encrypted columns document the search/sort caveat</li></ul><hr><h2 id="related-rfcs" tabindex="-1">Related RFCs <a class="header-anchor" href="#related-rfcs" aria-label="Permalink to &quot;Related RFCs&quot;">​</a></h2><ul><li><a href="./../rfcs/0006-deployment-upgrade-strategy.html">RFC 0006 — Deployment &amp; upgrade strategy</a></li><li><a href="./../rfcs/0007-user-data-portability.html">RFC 0007 — User data portability</a></li><li><a href="./../rfcs/0004-per-plugin-database.html">RFC 0004 — Per-plugin database</a></li><li><a href="./../rfcs/0033-user-data-deletion.html">RFC 0033 — User data deletion</a></li><li><a href="./../rfcs/0008-security-encryption-architecture.html">RFC 0008 — Security &amp; encryption architecture</a></li></ul><h2 id="related-docs" tabindex="-1">Related Docs <a class="header-anchor" href="#related-docs" aria-label="Permalink to &quot;Related Docs&quot;">​</a></h2><ul><li><a href="./../plugin-database.html">plugin-database.md</a></li><li><a href="./../self-hosting.html">self-hosting.md — Backup &amp; restore, upgrade</a></li><li><a href="./../upgrade.html">upgrade.md</a></li></ul><h2 id="cross-references" tabindex="-1">Cross-references <a class="header-anchor" href="#cross-references" aria-label="Permalink to &quot;Cross-references&quot;">​</a></h2><ul><li>Per-plugin database (epic task 3.13) is also tracked in <a href="./plugins-runtime.html">Plugins Runtime</a>.</li><li>User data deletion (epic task 1.7) is also tracked in <a href="./users-auth.html">Users &amp; Auth</a> (it extends <code>sdk.portability</code>).</li><li>Security hardening Tier 0+1 is tracked in <a href="./platform-shell.html">Platform Shell</a> (no crypto machinery in v1).</li></ul>',46)])])}const g=t(o,[["render",s]]);export{h as __pageData,g as default};
